class Student {
    String name;
    int score;

    void printInfo() {
        System.out.println("이름: " + name);
        System.out.println("점수: " + score);
    }
}

public class Main {
    public static void main(String[] args) {
        Student student = new Student();
        student.name = "Kim";
        student.score = 90;
        student.printInfo();
    }
}

